using System;
using System.Collections.Specialized;
using System.Collections.ObjectModel;
using System.Text;
using System.Drawing;
using System.Drawing.Imaging;
using System.IO;
using System.Reflection;
using NUnit.Framework;
using Tawala.XmlSupport;
using Tawala.RtfSupport;

namespace TawalaTest.RtfSupportTest
{
	[TestFixture]
	public class RtfMetafileTest
	{
		BindingFlags flags =
			BindingFlags.NonPublic |
			BindingFlags.Public |
			BindingFlags.Static |
			BindingFlags.Instance;

		private object getFieldValue(string name, object source)
		{
			FieldInfo fieldInfo = source.GetType().GetField(name, flags);
			return fieldInfo.GetValue(source);
		}

		private Collection<MetafileRecord> getRecords(RtfMetafile metafile)
		{
			return (Collection<MetafileRecord>)getFieldValue("records", metafile);
		}

        private Bitmap getBitmap(RtfMetafile metafile)
        {
            return (Bitmap)getFieldValue("bitmap", metafile);
        }

		private Tawala.RtfSupport.MetafileHeader getHeader(RtfMetafile metafile)
		{
			return (Tawala.RtfSupport.MetafileHeader)getFieldValue("header", metafile);
		}

		/// <summary>
		/// This string represent a standard windows metafile containing, as one of its elements, a bitmap created by inserting a PNG file into
		/// the TX Text control. The bitmap is a 10 x 12 solid rectangle, each pixel of which has the color (r:0xff, g:0x7e, b:0x3d).
		/// </summary>
		private string wmfFileStringFromPng =
			"";

		[Test]
		public void ConstructFromPng()
		{
			RtfMetafile metafile = new RtfMetafile(wmfFileStringFromPng);

			string expectedBase64PngString =
				"iVBORw0KGgoAAAANSUhEUgAAAAoAAAAMCAIAAADUCbv3AAAAAXNSR0IArs4c6QAAAARnQU1BAACx\r\n" +
				"jwv8YQUAAAAgY0hSTQAAeiYAAICEAAD6AAAAgOgAAHUwAADqYAAAOpgAABdwnLpRPAAAABpJREFU\r\n" +
				"KFNj/F9ny4AHAKXxIIZRaWzhQyBYAFsXv6i+LNJ8AAAAAElFTkSuQmCC";

			Assert.AreEqual(expectedBase64PngString, metafile.Base64PngString);

			Assert.AreEqual(10, metafile.Width);
			Assert.AreEqual(12, metafile.Height);
		}

		[Test]
		public void GetRecordsFromPng()
		{
			RtfMetafile metafile = new RtfMetafile(wmfFileStringFromPng);

			Assert.AreEqual(11, getRecords(metafile).Count);

			for (int i = 0; i < getRecords(metafile).Count; i++)
			{
				Assert.AreEqual(getRecords(metafile)[i].Size - 3, getRecords(metafile)[i].ParametersLength, "Record index = " + i);
			}

			Assert.AreEqual(0x0107, getRecords(metafile)[0].Function);
			Assert.AreEqual(0x00f7, getRecords(metafile)[1].Function);
			Assert.AreEqual(0x0234, getRecords(metafile)[2].Function);
			Assert.AreEqual(0x0035, getRecords(metafile)[3].Function);
			Assert.AreEqual(0x020b, getRecords(metafile)[4].Function);
			Assert.AreEqual(0x020c, getRecords(metafile)[5].Function);
			Assert.AreEqual(0x0940, getRecords(metafile)[6].Function);
			Assert.AreEqual(0x00f7, getRecords(metafile)[7].Function);
			Assert.AreEqual(0x0234, getRecords(metafile)[8].Function);
			Assert.AreEqual(0x01f0, getRecords(metafile)[9].Function);
			Assert.AreEqual(0x0000, getRecords(metafile)[10].Function);
		}

		/// <summary>
		/// This string represent a standard windows metafile containing, as one of its elements, a bitmap created by inserting a GIF file into
		/// the TX Text control. The bitmap is a 10 x 12 solid rectangle, each pixel of which has the color (r:0xff, g:0x7e, b:0x3d).
		/// </summary>
		string wmfFileStringFromGif =
			"";

		[Test]
		public void ConstructFromGif()
		{
			RtfMetafile metafile = new RtfMetafile(wmfFileStringFromGif);

			string expectedBase64PngString =
				"iVBORw0KGgoAAAANSUhEUgAAAAoAAAAMCAMAAABstdySAAAAAXNSR0IArs4c6QAAAARnQU1BAACx\r\n" +
				"jwv8YQUAAAAgY0hSTQAAeiYAAICEAAD6AAAAgOgAAHUwAADqYAAAOpgAABdwnLpRPAAAAwBQTFRF\r\n" +
				"/349AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA\r\n" +
				"AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAi9cf2wAAAAxJREFUGFdjYBh4AAAAhAABlny8ZQAA\r\n" +
				"AABJRU5ErkJggg==";

			Assert.AreEqual(expectedBase64PngString, metafile.Base64PngString);

			Assert.AreEqual(10, metafile.Width);
			Assert.AreEqual(12, metafile.Height);
		}

		[Test]
		public void GetHeaderFromGif()
		{
			RtfMetafile metafile = new RtfMetafile(wmfFileStringFromGif);

			Assert.AreEqual(1, getHeader(metafile).FileType);
			Assert.AreEqual(9, getHeader(metafile).HeaderSize);
			Assert.AreEqual(0x300, getHeader(metafile).Version);
			Assert.AreEqual(645, getHeader(metafile).FileSize);
			Assert.AreEqual(0, getHeader(metafile).NumOfObjects);
			Assert.AreEqual(618, getHeader(metafile).MaxRecordSize);
			Assert.AreEqual(0, getHeader(metafile).NumOfParams);
		}

		[Test]
		public void GetRecordsFromGif()
		{
			RtfMetafile metafile = new RtfMetafile(wmfFileStringFromGif);

			Assert.AreEqual(5, getRecords(metafile).Count);

			for (int i = 0; i < getRecords(metafile).Count; i++)
			{
				Assert.AreEqual(getRecords(metafile)[i].Size - 3, getRecords(metafile)[i].ParametersLength, "Record index = " + i);
			}

			Assert.AreEqual(0x020b, getRecords(metafile)[0].Function);
			Assert.AreEqual(0x020c, getRecords(metafile)[1].Function);
			Assert.AreEqual(0x0107, getRecords(metafile)[2].Function);
			Assert.AreEqual(0x0f43, getRecords(metafile)[3].Function);
			Assert.AreEqual(0x0000, getRecords(metafile)[4].Function);
		}

		[Test]
		public void GetBitmapFromGif()
		{
			RtfMetafile metafile = new RtfMetafile(wmfFileStringFromGif);

			Bitmap bitmap = getBitmap(metafile);

			Assert.AreEqual(10, bitmap.Width);
			Assert.AreEqual(12, bitmap.Height);
		}

		[Test]
		public void GetBitmapFromGradientGif()
		{
			/// <summary>
			/// This string represent a standard windows metafile containing, as one of its elements, a bitmap created by inserting a GIF file into
			/// the TX Text control. The bitmap is an 8 x 1 horizontal line. The R, G and B values of the 8 pixels are as follows:
			/// 
			/// Pixel 1: (r:0x01, g:0x01, b:0x01)
			/// Pixel 2: (r:0x02, g:0x02, b:0x02)
			/// Pixel 3: (r:0x03, g:0x03, b:0x03)
			/// Pixel 4: (r:0x04, g:0x04, b:0x04)
			/// Pixel 5: (r:0x05, g:0x05, b:0x05)
			/// Pixel 6: (r:0x06, g:0x06, b:0x06)
			/// Pixel 7: (r:0x07, g:0x07, b:0x07)
			/// Pixel 8: (r:0x08, g:0x08, b:0x08)
			/// 
			/// </summary>
			string wmfFileString =
				"";

			RtfMetafile metafile = new RtfMetafile(wmfFileString);

            Bitmap bitmap = getBitmap(metafile);

			Assert.AreEqual(8, bitmap.Width);
			Assert.AreEqual(1, bitmap.Height);
		}

		private string xmlMetafileString =
			"<image w=\"265\" h=\"318\" wgoal=\"150\" hgoal=\"180\" scalex=\"100\" scaley=\"100\" upi=\"96\">" +
			"<metafileHeader fileType=\"1\" headerSize=\"9\" version=\"768\" fileSize=\"827\" numOfObjects=\"2\" maxRecordSize=\"517\" numOfParams=\"0\" />\r\n" +
			"<metafileRecord size=\"5\" function=\"263\">03000000</metafileRecord>\r\n" +
			"<metafileRecord size=\"517\" function=\"247\"></metafileRecord>\r\n" +
			"<metafileRecord size=\"4\" function=\"564\">0000</metafileRecord>\r\n" +
			"<metafileRecord size=\"3\" function=\"53\"></metafileRecord>\r\n" +
			"<metafileRecord size=\"5\" function=\"523\">00000000</metafileRecord>\r\n" +
			"<metafileRecord size=\"5\" function=\"524\">0c000a00</metafileRecord>\r\n" +
			"<metafileRecord size=\"223\" function=\"2368\"></metafileRecord>\r\n" +
			"<metafileRecord size=\"45\" function=\"247\">0003140000000000800000000080000080800000000080008000800000808000c0c0c000c0dcc000a6caf000fffbf000a0a0a40080808000ff00000000ff0000ffff00000000ff00ff00ff0000ffff00ffffff00</metafileRecord>\r\n" +
			"<metafileRecord size=\"4\" function=\"564\">0100</metafileRecord>\r\n" +
			"<metafileRecord size=\"4\" function=\"496\">0000</metafileRecord>\r\n" +
			"<metafileRecord size=\"3\" function=\"0\"></metafileRecord>\r\n" +
			"</image>";

		private RtfMetafile getRtfMetafileFromXml()
		{
			IXmlElement element = new XmlElement(xmlMetafileString);
			RtfMetafile metafile = new RtfMetafile(element);
			return metafile;
		}

		[Test]
		public void ConstructFromXml()
		{
			RtfMetafile metafile = getRtfMetafileFromXml();

			Assert.AreEqual(1, getHeader(metafile).FileType);
			Assert.AreEqual(9, getHeader(metafile).HeaderSize);
			Assert.AreEqual(768, getHeader(metafile).Version);
			Assert.AreEqual(827, getHeader(metafile).FileSize);
			Assert.AreEqual(2, getHeader(metafile).NumOfObjects);
			Assert.AreEqual(517, getHeader(metafile).MaxRecordSize);
			Assert.AreEqual(0, getHeader(metafile).NumOfParams);

			Assert.AreEqual(11, getRecords(metafile).Count);
			Assert.AreEqual(5, getRecords(metafile)[0].Size);
			Assert.AreEqual(263, getRecords(metafile)[0].Function);
			Assert.AreEqual("<metafileRecord size=\"5\" function=\"263\">03000000</metafileRecord>\r\n", getRecords(metafile)[0].ToXml());

			string expectedBase64PngString =
			    "iVBORw0KGgoAAAANSUhEUgAAAAoAAAAMCAIAAADUCbv3AAAAAXNSR0IArs4c6QAAAARnQU1BAACx\r\n" +
			    "jwv8YQUAAAAgY0hSTQAAeiYAAICEAAD6AAAAgOgAAHUwAADqYAAAOpgAABdwnLpRPAAAABpJREFU\r\n" +
			    "KFNj/F9ny4AHAKXxIIZRaWzhQyBYAFsXv6i+LNJ8AAAAAElFTkSuQmCC";

			Assert.AreEqual(expectedBase64PngString, metafile.Base64PngString);

			Assert.AreEqual(10, metafile.Width);
			Assert.AreEqual(12, metafile.Height);
		}

		[Test]
		public void GetXml()
		{
			RtfMetafile metafile = getRtfMetafileFromXml();

			Assert.AreEqual(xmlMetafileString, metafile.ToXml());
		}

		[Test]
		public void GetHeaderAsHexString()
		{
			RtfMetafile metafile = getRtfMetafileFromXml();

			Assert.AreEqual("0100090000033b0300000200050200000000", metafile.Header.ToHexString());
		}

		[Test]
		public void GetOneRecordAsHexString()
		{
			RtfMetafile metafile = getRtfMetafileFromXml();

			Assert.AreEqual("05000000070103000000", metafile.Records[0].ToHexString());
		}

		[Test]
		public void GetMetafileAsHexString()
		{
			RtfMetafile metafile = getRtfMetafileFromXml();
		
			Assert.AreEqual(wmfFileStringFromPng, metafile.ToHexString());
		}
	}
}
